+
+	if (attach) {
+		await new Promise<void>((resolve, reject) => {
+			const child = spawn("tmux", ["attach-session", "-t", SESSION], {
+				stdio: "inherit",
+				shell: false,
+			});
+			child.on("error", reject);
+			child.on("exit", (code) => {
+				if (code === 0) resolve();
